const hamburgerBtn=document.getElementById('hamburgerBtn');const navMenu=document.getElementById('navMenu');const navLinks=document.querySelectorAll('.nav-links a');if(hamburgerBtn){hamburgerBtn.addEventListener('click',()=>{hamburgerBtn.classList.toggle('active');navMenu.classList.toggle('active');hamburgerBtn.setAttribute('aria-expanded',navMenu.classList.contains('active'));});}navLinks.forEach(link=>{link.addEventListener('click',()=>{hamburgerBtn.classList.remove('active');navMenu.classList.remove('active');hamburgerBtn.setAttribute('aria-expanded','false');});});document.addEventListener('click',(e)=>{if(!e.target.closest('nav')){hamburgerBtn.classList.remove('active');navMenu.classList.remove('active');hamburgerBtn.setAttribute('aria-expanded','false');}});const themeToggle=document.getElementById('themeToggle');const themeIcon=document.getElementById('themeIcon');const currentTheme=localStorage.getItem('theme')|| 'dark-mode';if(currentTheme==='light-mode'){document.body.classList.add('light-mode');if(themeIcon)themeIcon.textContent='◐';}else{document.body.classList.remove('light-mode');if(themeIcon)themeIcon.textContent='☀';}if(themeToggle){themeToggle.addEventListener('click',()=>{document.body.classList.toggle('light-mode');if(document.body.classList.contains('light-mode')){localStorage.setItem('theme','light-mode');if(themeIcon)themeIcon.textContent='◐';}else{localStorage.setItem('theme','dark-mode');if(themeIcon)themeIcon.textContent='☀';}});}document.addEventListener('DOMContentLoaded',()=>{const currentPage=window.location.pathname.split('/').pop()|| 'index.html';const navLinks=document.querySelectorAll('.nav-link');navLinks.forEach(link=>{const href=link.getAttribute('href');if(href===currentPage ||(currentPage==='' && href==='index.html')){link.classList.add('active');}else{link.classList.remove('active');}});});const filterBtns=document.querySelectorAll('.filter-btn');const projectCards=document.querySelectorAll('.project-card');filterBtns.forEach(btn=>{btn.addEventListener('click',()=>{const filter=btn.getAttribute('data-filter');filterBtns.forEach(b=>b.classList.remove('active'));btn.classList.add('active');projectCards.forEach(card=>{if(filter==='all' || card.getAttribute('data-category')===filter){card.style.display='flex';card.style.animation='fadeIn 0.6s ease';}else{card.style.display='none';}});});});const contactForm=document.getElementById('contactForm');const formConfirmation=document.getElementById('formConfirmation');const emailjsReady=()=>{try{if(typeof emailjs !=='undefined'){emailjs.init('YOUR_PUBLIC_KEY');}}catch(e){console.warn('EmailJS not initialized - contact form will not send emails');}};emailjsReady();if(contactForm){contactForm.addEventListener('submit',async(e)=>{e.preventDefault();const formData={from_name:document.getElementById('name').value,from_email:document.getElementById('email').value,message:document.getElementById('message').value,to_email:'nikhilmaurya.work@icloud.com'};try{const response=await emailjs.send('YOUR_SERVICE_ID','YOUR_TEMPLATE_ID',formData);if(response.status===200){contactForm.style.display='none';formConfirmation.classList.add('show');setTimeout(()=>{contactForm.reset();contactForm.style.display='block';formConfirmation.classList.remove('show');},5000);}}catch(error){console.error('Error sending email:',error);contactForm.style.display='none';formConfirmation.classList.add('show');setTimeout(()=>{contactForm.reset();contactForm.style.display='block';formConfirmation.classList.remove('show');},5000);}});}const cards=document.querySelectorAll('.highlight-card,.project-card,.experience-card,.social-card');cards.forEach(card=>{card.addEventListener('mouseenter',function(){this.style.transition='all 0.4s cubic-bezier(0.4,0,0.2,1)';});});const observerOptions={threshold:0.1,rootMargin:'0px 0px -50px 0px'};const observer=new IntersectionObserver((entries)=>{entries.forEach((entry,index)=>{if(entry.isIntersecting){setTimeout(()=>{entry.target.classList.add('animate');},index * 100);observer.unobserve(entry.target);}});},observerOptions);document.addEventListener('DOMContentLoaded',()=>{const animatableElements=document.querySelectorAll('.highlight-card,.project-card,.social-card,.timeline-item,.section-header');animatableElements.forEach(element=>{observer.observe(element);});});document.querySelectorAll('a[href^="#"]').forEach(anchor=>{anchor.addEventListener('click',function(e){const href=this.getAttribute('href');if(href !=='#'){e.preventDefault();const target=document.querySelector(href);if(target){target.scrollIntoView({behavior:'smooth',block:'start'});}}});});document.addEventListener('keydown',(e)=>{if(e.key==='Tab'){document.body.classList.add('keyboard-nav');}});document.addEventListener('mousedown',()=>{document.body.classList.remove('keyboard-nav');});